final:
module top_module (
    input [1:0] c,
    output reg d
);
  wire [1:0] _tap_c = c & {2{1'b1}};


    always @(*) begin
        case (c)
            2'b00: d = 1;
            2'b01: d = 0;
            2'b10: d = 0;
            2'b11: d = 1;
            default: d = 0; // Default case
        endcase
    end
endmodule
